import React, { useState } from 'react'
import { Container, Grid, Paper, TextField, makeStyles, Button, IconButton, Tooltip, Typography, Dialog, DialogContent, DialogContentText, DialogActions, useTheme, useMediaQuery } from '@material-ui/core'
import StudentActivities from '../components/StudentActivities'
import { Assignment, AttachFileRounded } from '@material-ui/icons'
import { useLocation, useNavigate } from 'react-router-dom'
import axios from 'axios'

const useStyle = makeStyles(theme => {
    return {
        paper: {
            padding: theme.spacing(2)
        },
        input: {
            display: 'none'
        }
    }
})

export default function TeacherFeed() {
    const classes = useStyle()
    const theme = useTheme();

    const location = useLocation()
    const subject = location.search.slice(1)
    const subjectName = subject.replace('%20', ' ')

    // const [open, setOpen] = React.useState(false);
    // const fullScreen = useMediaQuery(theme.breakpoints.down('sm'));

    // const handleClickOpen = () => {
    //     setOpen(true);
    // };

    // const handleClose = () => {
    //     setOpen(false);
    // };

    const [data, setData] = useState({
        title: '',
        instructor: '',
        yearSection: ''
    })
    
    const handleChange = (event) => {
        const name = event.target.name;
        const value = event.target.value;
    
        setData(data => ({...data, [name]: value}));
    }
    
      const handleSubmit = (event) => {
        event.preventDefault();
    
        const sendData = {
            title:data.title,
            instructor:data.instructor,
            yearSection:data.yearSection
        }
        
        
        axios.post('http://localhost:80/api/classrooms.php', sendData)
            .then((result) => {
                console.log(result.data)
                if(result.data.Status == 'Invalid') {
                    alert('Invalid User');
                } else {
                    navigate('/teacherDashboard')
                }
            })
      }


    const [activities, setActivities] = useState([
        { title: 'Assignment 1 mahaba mabahaba', body: 'May 11', id: 1 },
        { title: 'Assignment 2 mahaba mabahaba', body: 'May 2', id: 2 },
        { title: 'Assignment 3 mahaba mabahaba', body: 'May 3', id: 3 },
        { title: 'Assignment 4 mahaba mabahaba', body: 'May 4', id: 4 },
        { title: 'Assignment 5 mahaba mabahaba', body: 'May 5', id: 5 },
        { title: 'Assignment 6 mahaba mabahaba', body: 'May 6', id: 6 },
        { title: 'Assignment 7 mahaba mabahaba', body: 'May 7', id: 7 },
        { title: 'Assignment 8 mahaba mabahaba', body: 'May 8', id: 8 },
        { title: 'Assignment 9 mahaba mabahaba', body: 'May 9', id: 9 },
        { title: 'Assignment 10 mahaba mabahaba', body: 'May 10', id: 10 },
    ])

    return (
        <>
            <Container maxWidth='sm'>
                <Grid container spacing={3}>

                    <Grid item xs={12}>
                        <h1>{subjectName}</h1>
                        <p>BSCpE - 3A</p>
                    </Grid>

                    <Grid item xs={12}>
                        <Paper className={classes.paper} >
                            <Typography variant='h5'>
                                Create post
                            </Typography>

                            <TextField variant='filled' label='Classroom period' helperText="Prelim, Midterm, Finals, etc." margin='normal' fullWidth />

                            <TextField variant='filled' label='Title ' margin='normal' fullWidth />

                            <TextField variant='filled' color='secondary' label='Announcement' minRows={5} margin='normal' multiline fullWidth />

                            <div>
                                <input className={classes.input} type="file" accept='image/*' id='attach-file' />
                                <label htmlFor="attach-file">
                                    <IconButton component='span'><Tooltip title='Attach a file' placement='top' ><AttachFileRounded /></Tooltip></IconButton>
                                </label>
                                <IconButton component='span'><Tooltip title='Attach a Quiz form' placement='top' ><Assignment /></Tooltip></IconButton>
                            </div>

                            <div>
                                <Button variant='contained' color='secondary' size='large' onClick={handleClickOpen} fullWidth disableElevation >Post</Button>
                            </div>
                        </Paper>

                        {/* <Dialog
                            fullScreen={fullScreen}
                            open={open}
                            onClose={handleClose}
                        >
                            <DialogContent>
                                <DialogContentText>
                                    Are you sure you want to post this?
                                </DialogContentText>
                            </DialogContent>
                            <DialogActions>
                                <Button autoFocus onClick={handleClose} color="primary">
                                    Cancel
                                </Button>
                                <Button onClick={handleClose} color="primary" autoFocus>
                                    Confirm
                                </Button>
                            </DialogActions>
                        </Dialog> */}
                    </Grid>

                    {activities.map(activity => (
                        <Grid item xs={12} key={activity.id}>
                            <StudentActivities activity={activity} />
                        </Grid>
                    ))}

                </Grid>
            </Container>
        </>
    )
}
